// WR-05 Build Context v2 -- carry-forward, aging, open windows, Big 3
// ====================================================================

const todayCal       = $('Get Today Calendar').all();
const lookaheadCal   = $('Get Lookahead Calendar').all();
const emailsUnread   = $('Get Recent Emails').all();
let emailsAttention  = [];
try { emailsAttention = $('Get Needs-Attention Emails').all(); } catch (e) {}
let emailsSent = [];
try { emailsSent = $('Get Sent Awaiting Reply').all(); } catch (e) {}
let tasks = [];
try {
  const tasksRaw = $('Get Open Tasks').all();
  for (const r of tasksRaw) {
    const body = r.json || r;
    const results = body.results || (Array.isArray(body) ? body : []) || [];
    tasks = tasks.concat(results.map(p => ({ json: p })));
  }
} catch (e) { tasks = []; }

// --- Dismissed email patterns from Notion ---
let dismissedPatterns = [];
try {
  const dismissedRaw = $('Get Dismissed Emails').all();
  for (const r of dismissedRaw) {
    const body = r.json || r;
    const results = body.results || [];
    for (const p of results) {
      const props = p.properties || {};
      const subject = (props['Subject Pattern']?.title?.[0]?.plain_text || '').trim().toLowerCase();
      const sender  = (props['Sender']?.rich_text?.[0]?.plain_text || '').trim().toLowerCase();
      if (subject) dismissedPatterns.push({ subject, sender });
    }
  }
} catch (e) { dismissedPatterns = []; }

const isDismissed = (email) => {
  const subj = (email.subject || '').toLowerCase();
  const from  = (email.from  || '').toLowerCase();
  return dismissedPatterns.some(p => {
    if (!subj.includes(p.subject)) return false;
    if (p.sender && !from.includes(p.sender)) return false;
    return true;
  });
};

// --- Yesterday's brief for carry-forward ---
let yesterdayHotItems = [];
try {
  const yesterdayBriefs = $('Get Yesterday Brief').all();
  if (yesterdayBriefs.length > 0) {
    const brief = yesterdayBriefs[0].json || yesterdayBriefs[0];
    const body = brief.textPlain || brief.text || brief.snippet || '';
    // Extract Hot Items / Big 3 section
    const hotMatch = body.match(/(?:Hot Items|The Big 3|Big 3)([\s\S]*?)(?=\n##|\n#[^#]|Today's Schedule|Action List|$)/i);
    if (hotMatch) {
      const lines = hotMatch[1].split('\n').filter(l => /^\s*[-*\d.]/.test(l));
      yesterdayHotItems = lines.map(l => l.replace(/^[\s\-\*\d.]+/, '').trim()).filter(Boolean);
    }
  }
} catch (e) { /* no yesterday brief -- degrade gracefully */ }

// --- Slack activity (DMs + mentions, last ~30h) ---
let slackMessages = [];
try {
  const slackRaw = $('Get Slack Activity').all();
  for (const r of slackRaw) {
    const body = r.json || r;
    const matches = body.messages?.matches || [];
    for (const m of matches) {
      slackMessages.push({
        text: (m.text || '').slice(0, 500),
        user: m.username || m.user || 'unknown',
        channel: m.channel?.name || m.channel?.id || '',
        channelType: m.channel?.is_im ? 'DM' : (m.channel?.is_private ? 'private' : 'channel'),
        ts: m.ts ? new Date(parseFloat(m.ts) * 1000).toISOString() : '',
        permalink: m.permalink || ''
      });
    }
  }
} catch (e) { slackMessages = []; }

// --- Meeting prep: per-meeting Slack correlation ---
let meetingPrepAttendees = [];
let meetingPrepSlack = [];
try {
  const prepQ = $('Build Meeting Prep Query').first().json;
  meetingPrepAttendees = prepQ.attendees || [];
  const prepSlackRaw = $('Get Meeting Prep Slack').all();
  for (const r of prepSlackRaw) {
    const body = r.json || r;
    const matches = body.messages?.matches || [];
    for (const m of matches) {
      meetingPrepSlack.push({
        text: (m.text || '').slice(0, 600),
        user: m.username || m.user || 'unknown',
        channel: m.channel?.name || m.channel?.id || '',
        ts: m.ts ? new Date(parseFloat(m.ts) * 1000).toISOString() : '',
        permalink: m.permalink || ''
      });
    }
  }
} catch (e) { /* no prep data */ }

// --- Dedupe attention emails against unread ---
const unreadIds = new Set(emailsUnread.map(e => (e.json || e).id));
emailsAttention = emailsAttention.filter(e => !unreadIds.has((e.json || e).id));

// --- Helpers ---
const fmtTime = dt => dt
  ? new Date(dt).toLocaleString('en-US', {
      timeZone: 'America/Los_Angeles',
      hour: 'numeric', minute: '2-digit', hour12: true
    })
  : '';

const fmtDateTime = dt => dt
  ? new Date(dt).toLocaleString('en-US', {
      timeZone: 'America/Los_Angeles',
      weekday: 'short', month: 'short', day: 'numeric',
      hour: 'numeric', minute: '2-digit', hour12: true
    })
  : '';

const cleanEvent = e => {
  const j = e.json || e;
  const attendees = (j.attendees || [])
    .filter(a => !a.self)
    .map(a => a.displayName || a.email)
    .join(', ');
  return {
    title: j.summary || 'Untitled',
    start: j.start?.dateTime || j.start?.date || '',
    end:   j.end?.dateTime   || j.end?.date   || '',
    attendees,
    location: j.location || (j.conferenceData ? 'Video call' : ''),
    description: (j.description || '').slice(0, 300)
  };
};

// --- Compute open windows (30+ min gaps between 8 AM -- 6 PM PT) ---
const todayEvents = todayCal.map(cleanEvent);

const computeOpenWindows = (events) => {
  // Get current wall-clock in PT
  const nowPT = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Los_Angeles' }));
  const workStart = new Date(nowPT); workStart.setHours(8,0,0,0);
  const workEnd   = new Date(nowPT); workEnd.setHours(18,0,0,0);

  const slots = events
    .filter(e => e.start && e.end && !/^\d{4}-\d{2}-\d{2}$/.test(e.start))
    .map(e => ({ start: new Date(e.start), end: new Date(e.end), title: e.title }))
    .sort((a,b) => a.start - b.start);

  const windows = [];
  let cursor = workStart;
  for (const s of slots) {
    if (s.start > cursor) {
      const gap = (s.start - cursor) / 60000;
      if (gap >= 30) windows.push({ start: new Date(cursor), end: new Date(s.start), minutes: Math.round(gap) });
    }
    if (s.end > cursor) cursor = s.end;
  }
  if (cursor < workEnd) {
    const gap = (workEnd - cursor) / 60000;
    if (gap >= 30) windows.push({ start: new Date(cursor), end: workEnd, minutes: Math.round(gap) });
  }
  if (windows.length === 0 && slots.length === 0) windows.push({ label: 'All day open' });
  return windows;
};

const openWindows = computeOpenWindows(todayEvents);

const cleanEmail = e => {
  const j = e.json || e;
  let subject = j.Subject || j.subject || '';
  let from    = j.From    || j.from    || '';
  let date    = j.Date    || j.date    || '';
  if (!subject && j.payload?.headers) {
    const h = j.payload.headers;
    subject = h.find(x => x.name === 'Subject')?.value || '';
    from    = h.find(x => x.name === 'From')?.value    || '';
    date    = h.find(x => x.name === 'Date')?.value    || '';
  }
  if (!date && j.internalDate) date = new Date(parseInt(j.internalDate)).toISOString();
  const labels = (j.labels || j.labelIds || []).map(l => typeof l === 'string' ? l : (l.name || '')).join(',');
  let to = j.To || j.to || '';
  if (!to && j.payload?.headers) to = j.payload.headers.find(x => x.name === 'To')?.value || '';
  let daysSince = 0;
  if (date) daysSince = Math.floor((Date.now() - new Date(date).getTime()) / 86400000);
  return { subject: subject || '(no subject)', from: from || 'Unknown', to, date, labels, preview: (j.snippet || '').slice(0,250), daysSince };
};

const cleanTask = t => {
  const j = t.json || t;
  const p = j.properties || {};
  const title = p.Task?.title?.[0]?.plain_text
    || p['Task name']?.title?.[0]?.plain_text
    || p.Name?.title?.[0]?.plain_text
    || '(untitled task)';
  const status   = p.Status?.status?.name   || p.Status?.select?.name || '';
  const due      = p.Due?.date?.start       || '';
  const priority = p.Priority?.select?.name || '';
  const project  = p.Project?.select?.name  || '';
  const source   = p.Source?.rich_text?.[0]?.plain_text || '';
  const notes    = (p.Notes?.rich_text?.[0]?.plain_text || '').slice(0,200);
  let ageDays = 0;
  if (j.created_time) ageDays = Math.floor((Date.now() - new Date(j.created_time).getTime()) / 86400000);
  return { title, status, due, priority, project, source, notes, url: j.url || '', ageDays };
};

const lookaheadEvents  = lookaheadCal.map(cleanEvent).filter(e => e.title !== 'Untitled' || e.start);
const emailUnreadList  = emailsUnread.map(cleanEmail).filter(e => !isDismissed(e));
const emailAttentionList = emailsAttention.map(cleanEmail).filter(e => !isDismissed(e));

// --- Awaiting reply detection ---
const allOtherEmails = emailsUnread.concat(emailsAttention);
const repliedThreadIds = new Set();
for (const sent of emailsSent) {
  const sj = sent.json || sent;
  const sentDate = parseInt(sj.internalDate || '0');
  for (const other of allOtherEmails) {
    const oj = other.json || other;
    if (oj.threadId === sj.threadId && parseInt(oj.internalDate || '0') > sentDate) {
      repliedThreadIds.add(sj.threadId);
      break;
    }
  }
}
const sentAwaitingList = emailsSent
  .filter(e => !repliedThreadIds.has((e.json || e).threadId))
  .map(cleanEmail)
  .filter(e => !isDismissed(e));

// --- Tasks ---
const allTasks = tasks.map(cleanTask).filter(t => {
  const s = (t.status || '').toLowerCase();
  return s !== 'done' && s !== 'complete';
});
const standingTasks    = allTasks.filter(t => t.project === 'Personal' || t.project === 'Non-Sales Admin');
const nonStandingTasks = allTasks.filter(t => t.project !== 'Personal' && t.project !== 'Non-Sales Admin');
nonStandingTasks.sort((a,b) => (b.url || '').localeCompare(a.url || ''));
const taskList = nonStandingTasks.slice(0,100);

const tasksByProject = {};
for (const t of taskList) {
  const proj = t.project || '(no project)';
  if (!tasksByProject[proj]) tasksByProject[proj] = [];
  tasksByProject[proj].push(t);
}

// --- Dates ---
const todayLocal = new Date().toLocaleDateString('en-US', {
  timeZone: 'America/Los_Angeles',
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});
const dateISO = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Los_Angeles' });

// ===================================================================
// BUILD PROMPT
// ===================================================================
let p = `You are generating Sales User' Daily Prep Brief for ${todayLocal}.

# WHO Sales User IS
- Role: Business Development at sample_company. Reports to Executive Stakeholder.
- This inbox and calendar are 100% sample_company; treat every email and meeting as sample_company work unless clearly personal.
- Focus areas: sample_company rollup sourcing (power services -- solar/BESS O&M, electrical contractors), Example Company Business Development pipeline, Strategic Partnerships DD support.
- Key people: Executive Stakeholder (CEO, sample_company + Strategic Partnerships), Priority Contact (Shadow partner, industrial vertical), Devan Stakeholder (sample_company corp dev).
- Priority senders (flag any email from): Executive Stakeholder, Priority Contact, Devan Stakeholder, anyone identified as an acquisition target or rollup operator.

# OUTPUT FORMAT
Output Markdown with EXACTLY these section headers. No parenthetical descriptions on headers. Do NOT echo these instructions.

# Daily Prep Brief -- ${todayLocal}

## The Big 3
## Action List
## Today's Schedule
## Email Triage
## Slack Activity
## Open Tasks
## Don't Forget
## Dropped from Yesterday

# SECTION DEFINITIONS

## The Big 3
The 3 things that make today a win. Specific actions with a person or deliverable named. At least one must be strategic (advancing a deal, relationship, or project), not just inbox cleanup.

Format:
1. [action] -- [why it matters]
2. [action] -- [why it matters]
3. [action] -- [why it matters]

If truly nothing pressing: "Quiet day. Pick one strategic item to advance."

## Action List
Remaining actionable items beyond the Big 3. Each item gets:
- [Day N] age tag (use the age data provided for tasks; for emails, use the daysSince value)
- [STUCK?] if Day 3+ with no apparent progress
- [OVERDUE] if Day 7+
- Format: [Day N] action (who/what)
- Most urgent first, max 10 items
- If no items beyond Big 3: "Big 3 covers it."

## Today's Schedule
Two parts:

**Meetings**
For each meeting, output two lines:
Line 1: Time | Meeting | Key attendees
Line 2:   Prep: <2-3 specific items from MEETING PREP CONTEXT below -- recent Slack threads, decisions in flight, files mentioned, open questions. Cite channel names. If MEETING PREP CONTEXT has no hits for this meeting's attendees, write "Prep: no recent context found."

Skip meetings that are clearly personal (Ballet, etc.) -- list them at the end as "Personal: <title> at <time>".

**Open Windows**
Free blocks of 30+ minutes. Suggest which Action List items fit each window.
Use the OPEN WINDOWS data provided below -- do not recalculate.

## Email Triage
Two sub-lists:

**Awaiting My Reply**
- from -- subject -- what Sales User owes (one line)
- Pull from NEEDS-ATTENTION and UNREAD data

**Awaiting Their Reply**
- to -- subject -- N days since sent
- [NUDGE] tag if 7+ days silent
- Pull from SENT AWAITING REPLY data

Skip marketing, newsletters, system notifications, invites already on the schedule.
If both empty: "Inbox clear."

## Slack Activity
DMs and @mentions from the last ~24h. Group:

**Direct Messages**
- from -- channel (or "DM") -- one-line summary -- [Day N] if older than today
- Skip routine pings ("got it", "thx") unless they require a response

**Mentions in Channels**
- channel -- from -- one-line context of why Sales User was mentioned
- Flag anything that asks Sales User a direct question or assigns an action

If both empty: "Slack quiet."

## Open Tasks
Group by project in this order: Example Company Pipeline, Example Company Business Development, Strategic Partnerships, Operations, then the rest.
- Lead with P0/P1 and items due this week
- Use task name verbatim; add Notes fragment if it helps
- Include [Day N] age tag
- Omit empty projects
- Exclude Personal and Non-Sales Admin (those go in Don't Forget)

## Don't Forget
One bullet per standing item from STANDING ITEMS data. Sort by Priority then Due.
If none: "Nothing dropping off the radar."

## Dropped from Yesterday
Compare YESTERDAY'S ITEMS against today's data. List anything that was in yesterday's brief but does NOT appear in today's Big 3, Action List, or Open Tasks.
If nothing dropped or no yesterday data: "Everything carried forward or completed."

# RULES
- No em dashes (use -- for separators if needed), no emojis. Active voice. Short.
- Anything from Executive Stakeholder or Priority Contact gets surfaced.
- Acquisition target outreach (rollup pipeline) takes precedence over internal admin.
- Use the [Day N] age values from the data; do not guess.

`;

p += `\n=== INPUT DATA ===\n\n`;

// --- Yesterday carry-forward ---
p += `--- YESTERDAY'S ITEMS (for Dropped from Yesterday) ---\n`;
if (yesterdayHotItems.length > 0) {
  for (const item of yesterdayHotItems) p += `- ${item}\n`;
} else {
  p += `(No yesterday brief found. Write "No prior brief to compare." in Dropped from Yesterday.)\n`;
}

// --- Today's calendar ---
p += `\n--- TODAY'S CALENDAR (${todayEvents.length} events) ---\n`;
for (const e of todayEvents) {
  p += `${fmtTime(e.start)} - ${fmtTime(e.end)} | ${e.title}\n  attendees: ${e.attendees || '(none)'}\n  location: ${e.location || '(none)'}\n  desc: ${e.description}\n\n`;
}

p += `--- OPEN WINDOWS (30+ min gaps, 8 AM - 6 PM PT) ---\n`;
for (const w of openWindows) {
  if (w.label) { p += `${w.label}\n`; }
  else { p += `${fmtTime(w.start)} - ${fmtTime(w.end)} (${w.minutes} min)\n`; }
}

// --- Lookahead ---
p += `\n--- NEXT 5 DAYS (${lookaheadEvents.length} events) ---\n`;
for (const e of lookaheadEvents.slice(0,30)) {
  p += `${fmtDateTime(e.start)} | ${e.title} | ${e.attendees || '(no external)'}\n`;
}

// --- Emails ---
p += `\n--- UNREAD EMAILS LAST 22h (${emailUnreadList.length}) ---\n`;
for (const e of emailUnreadList) {
  p += `FROM: ${e.from}\nSUBJECT: ${e.subject}\nDATE: ${e.date} [${e.daysSince}d ago]\nPREVIEW: ${e.preview}\n---\n`;
}

p += `\n--- NEEDS-ATTENTION EMAILS 14d (${emailAttentionList.length}) ---\n`;
for (const e of emailAttentionList) {
  p += `FROM: ${e.from}\nSUBJECT: ${e.subject}\nDATE: ${e.date} [${e.daysSince}d ago]\nPREVIEW: ${e.preview}\n---\n`;
}

p += `\n--- SENT AWAITING REPLY (${sentAwaitingList.length}) ---\n`;
for (const e of sentAwaitingList) {
  p += `TO: ${e.to || e.from}\nSUBJECT: ${e.subject}\nSENT: ${e.date} [${e.daysSince}d ago]\nPREVIEW: ${e.preview}\n---\n`;
}

// --- Slack ---
p += `\n--- SLACK ACTIVITY (DMs + mentions, ${slackMessages.length}) ---\n`;
for (const m of slackMessages) {
  p += `[${m.channelType}] ${m.channel} | ${m.user} | ${m.ts}\n${m.text}\nlink: ${m.permalink}\n---\n`;
}

// --- Meeting Prep (per-attendee Slack hits, last 7d) ---
p += `\n--- MEETING PREP CONTEXT (today's external attendees, ${meetingPrepAttendees.length}) ---\n`;
if (meetingPrepAttendees.length === 0) {
  p += `(No external attendees on today's calendar.)\n`;
} else {
  for (const a of meetingPrepAttendees) {
    p += `\n[Attendee: ${a.slackRealName || a.calendarName || a.email}${a.email ? ' <' + a.email + '>' : ''}${a.slackId ? ' slack:' + a.slackId : ''}]\n`;
    p += `Meetings today: ${a.eventTitles.join('; ')}\n`;
    const matchTerms = [a.slackRealName, a.calendarName, a.slackDisplayName, a.slackUsername]
      .filter(Boolean).map(s => s.toLowerCase());
    const hits = meetingPrepSlack.filter(m => {
      const txt = (m.text || '').toLowerCase();
      const usr = (m.user || '').toLowerCase();
      if (a.slackId && (txt.includes(a.slackId.toLowerCase()) || usr === a.slackUsername.toLowerCase())) return true;
      return matchTerms.some(t => t && (txt.includes(t) || usr.includes(t.split(' ')[0])));
    });
    if (hits.length === 0) {
      p += `Recent Slack: (none found in last 7d)\n`;
    } else {
      p += `Recent Slack (top ${Math.min(hits.length, 6)}):\n`;
      for (const h of hits.slice(0, 6)) {
        p += `  [${h.channel}] ${h.user} ${h.ts.slice(0,10)}: ${h.text.slice(0, 250).replace(/\n/g, ' ')}\n`;
        if (h.permalink) p += `    ${h.permalink}\n`;
      }
    }
  }
}

// --- Tasks ---
p += `\n--- STANDING ITEMS (${standingTasks.length}) ---\n`;
for (const t of standingTasks) {
  p += `[${t.project}] ${t.priority || '--'} | [${t.status}] ${t.title} | due: ${t.due || '(none)'} | age: ${t.ageDays}d\n`;
  if (t.notes) p += `  notes: ${t.notes}\n`;
  if (t.source) p += `  source: ${t.source}\n`;
}

p += `\n--- OPEN TASKS (${taskList.length}) ---\n`;
const projectOrder = ['Example Company Pipeline','Example Company Business Development','Strategic Partnerships','Operations'];
const seenProjects = new Set();
for (const proj of projectOrder) {
  if (!tasksByProject[proj]) continue;
  seenProjects.add(proj);
  p += `\n[${proj}]\n`;
  for (const t of tasksByProject[proj]) {
    p += `  ${t.priority || '--'} | [${t.status}] ${t.title} | due: ${t.due || '(none)'} | age: ${t.ageDays}d\n`;
    if (t.notes) p += `    notes: ${t.notes}\n`;
    if (t.source) p += `    source: ${t.source}\n`;
  }
}
for (const proj of Object.keys(tasksByProject)) {
  if (seenProjects.has(proj)) continue;
  p += `\n[${proj}]\n`;
  for (const t of tasksByProject[proj]) {
    p += `  ${t.priority || '--'} | [${t.status}] ${t.title} | due: ${t.due || '(none)'} | age: ${t.ageDays}d\n`;
    if (t.notes) p += `    notes: ${t.notes}\n`;
  }
}

return [{ json: { prompt: p, todayLocal, dateISO, eventCount: todayEvents.length, emailCount: emailUnreadList.length + emailAttentionList.length, taskCount: taskList.length } }];

// Format Output v2 -- updated header for Daily Prep Brief v2
const llm = $input.first().json;
const ctx = $('Build Context').first().json;
const text = llm.text || llm.output || llm.response || llm.content || '';
const todayLocal = ctx.todayLocal;
const dateISO = ctx.dateISO;

// Markdown to HTML
const escapeHtml = s => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const lines = text.split('\n');
let html = '';
let inList = false;
let inOl = false;
for (const raw of lines) {
  const line = raw.trimEnd();
  // Ordered list items (1. 2. 3.)
  const olMatch = line.match(/^(\d+)\.\s+(.+)/);
  if (line.startsWith('# ')) {
    if (inList) { html += '</ul>'; inList = false; }
    if (inOl)   { html += '</ol>'; inOl = false; }
    html += `<h1 style="font-size:18px;margin:18px 0 8px;color:#1a3a5c;">${escapeHtml(line.slice(2))}</h1>`;
  } else if (line.startsWith('## ')) {
    if (inList) { html += '</ul>'; inList = false; }
    if (inOl)   { html += '</ol>'; inOl = false; }
    html += `<h2 style="font-size:15px;margin:14px 0 6px;color:#1a3a5c;border-bottom:1px solid #e5e7eb;padding-bottom:4px;">${escapeHtml(line.slice(3))}</h2>`;
  } else if (line.startsWith('### ')) {
    if (inList) { html += '</ul>'; inList = false; }
    if (inOl)   { html += '</ol>'; inOl = false; }
    html += `<h3 style="font-size:13px;margin:10px 0 4px;color:#374151;">${escapeHtml(line.slice(4))}</h3>`;
  } else if (line.startsWith('- ') || line.startsWith('* ')) {
    if (inOl) { html += '</ol>'; inOl = false; }
    if (!inList) { html += '<ul style="margin:4px 0 8px 20px;padding:0;">'; inList = true; }
    let bullet = line.slice(2);
    bullet = bullet.replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
    // Highlight age tags
    bullet = bullet.replace(/\[(Day \d+)\]/g, '<span style="color:#9333ea;font-weight:600;">[$1]</span>');
    bullet = bullet.replace(/\[STUCK\?\]/g, '<span style="color:#dc2626;font-weight:700;">[STUCK?]</span>');
    bullet = bullet.replace(/\[OVERDUE\]/g, '<span style="color:#dc2626;font-weight:700;">[OVERDUE]</span>');
    bullet = bullet.replace(/\[NUDGE\]/g, '<span style="color:#d97706;font-weight:600;">[NUDGE]</span>');
    html += `<li style="margin:3px 0;font-size:13px;line-height:1.5;">${bullet}</li>`;
  } else if (olMatch) {
    if (inList) { html += '</ul>'; inList = false; }
    if (!inOl) { html += '<ol style="margin:4px 0 8px 20px;padding:0;">'; inOl = true; }
    let item = olMatch[2];
    item = item.replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
    html += `<li style="margin:3px 0;font-size:13px;line-height:1.5;">${item}</li>`;
  } else if (line === '') {
    if (inList) { html += '</ul>'; inList = false; }
    if (inOl)   { html += '</ol>'; inOl = false; }
  } else {
    if (inList) { html += '</ul>'; inList = false; }
    if (inOl)   { html += '</ol>'; inOl = false; }
    let para = escapeHtml(line);
    para = para.replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
    html += `<p style="margin:6px 0;font-size:13px;line-height:1.5;">${para}</p>`;
  }
}
if (inList) html += '</ul>';
if (inOl) html += '</ol>';

const fullHtml = `
<div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;max-width:680px;margin:0 auto;color:#222;">
  <div style="background:#1a3a5c;padding:18px 22px;border-radius:8px 8px 0 0;">
    <h1 style="margin:0;color:#fff;font-size:18px;font-weight:600;">Daily Prep Brief</h1>
    <p style="margin:3px 0 0;color:#a8c4e0;font-size:12px;">${todayLocal}</p>
  </div>
  <div style="padding:20px 24px;background:#fff;border:1px solid #e5e7eb;border-top:none;border-radius:0 0 8px 8px;">
    ${html}
  </div>
  <p style="font-size:10px;color:#aaa;text-align:center;margin-top:10px;">Generated by n8n WR-05 v2</p>
</div>`;

// Notion blocks (same logic, capped at 100)
const stripBold = s => String(s).replace(/\*\*([^*]+)\*\*/g, '$1');
const para_b  = content => ({ object:'block', type:'paragraph', paragraph: { rich_text: [{ type:'text', text:{ content: stripBold(content).slice(0,1900) } }] } });
const heading_b = (level, content) => ({ object:'block', type:`heading_${level}`, [`heading_${level}`]: { rich_text: [{ type:'text', text:{ content: stripBold(content).slice(0,1900) } }] } });
const bullet_b = content => ({ object:'block', type:'bulleted_list_item', bulleted_list_item: { rich_text: [{ type:'text', text:{ content: stripBold(content).slice(0,1900) } }] } });
const numbered_b = content => ({ object:'block', type:'numbered_list_item', numbered_list_item: { rich_text: [{ type:'text', text:{ content: stripBold(content).slice(0,1900) } }] } });

const blocks = [];
let buffer = '';
const flushBuffer = () => {
  if (!buffer.trim()) { buffer = ''; return; }
  blocks.push(para_b(buffer.trim()));
  buffer = '';
};
for (const raw of text.split('\n')) {
  const line = raw.trimEnd();
  const olM = line.match(/^\d+\.\s+(.+)/);
  if (line.startsWith('# '))       { flushBuffer(); blocks.push(heading_b(1, line.slice(2))); }
  else if (line.startsWith('## '))  { flushBuffer(); blocks.push(heading_b(2, line.slice(3))); }
  else if (line.startsWith('### ')){ flushBuffer(); blocks.push(heading_b(3, line.slice(4))); }
  else if (line.startsWith('- ') || line.startsWith('* ')) { flushBuffer(); blocks.push(bullet_b(line.slice(2))); }
  else if (olM) { flushBuffer(); blocks.push(numbered_b(olM[1])); }
  else if (line === '') { flushBuffer(); }
  else { buffer = buffer ? buffer + '\n' + line : line; }
}
flushBuffer();

const childrenBlocks = blocks.slice(0, 100);
const notionPayload = {
  parent: { database_id: 'fa34c367-333f-4254-8fdf-ce8961b6e7f4' },
  properties: {
    Date:   { title: [{ text: { content: dateISO } }] },
    Status: { select: { name: 'Generated' } }
  },
  children: childrenBlocks
};

return [{
  json: {
    subject: `Daily Prep Brief - ${todayLocal}`,
    html: fullHtml,
    rawText: text,
    dateISO,
    notionTitle: dateISO,
    notionPayload
  }
}];

// Resolve calendar attendee emails to Slack users via handle/first-name match.
// (Slack OAuth scope doesn't include email-on-list, so match by email local part.)
const events = $('Get Today Calendar').all();
const Sales User_EMAILS = new Set(['sales.user@example.com', 'sales.user@example.com', 'sales.user']);

let slackUsers = [];
try {
  const usersRaw = $('Get Slack Users').all();
  for (const r of usersRaw) {
    const body = r.json || r;
    const members = body.members || [];
    for (const m of members) {
      if (m.deleted || m.is_bot || m.id === 'USLACKBOT') continue;
      slackUsers.push(m);
    }
  }
} catch (e) {}

const buildFullName = (m) => {
  const fn = m.profile?.first_name || '';
  const ln = m.profile?.last_name || '';
  const dn = m.profile?.display_name || '';
  if (fn && ln) return `${fn} ${ln}`.trim();
  if (m.real_name) return m.real_name;
  if (dn) return dn;
  return m.name || '';
};

const resolveAttendee = (email) => {
  const local = email.split('@')[0].toLowerCase();
  // 1. Slack handle (`name`) exact match
  let m = slackUsers.find(u => (u.name || '').toLowerCase() === local);
  if (m) return m;
  // 2. first_name exact match (lowercased)
  const firstMatches = slackUsers.filter(u => (u.profile?.first_name || '').toLowerCase() === local);
  if (firstMatches.length === 1) return firstMatches[0];
  // 3. handle starts with local part
  m = slackUsers.find(u => (u.name || '').toLowerCase().startsWith(local));
  if (m) return m;
  return null;
};

const attendeesByEmail = new Map();
for (const e of events) {
  const ev = e.json || e;
  const title = ev.summary || '';
  for (const a of (ev.attendees || [])) {
    if (a.self) continue;
    const email = (a.email || '').toLowerCase();
    if (Sales User_EMAILS.has(email)) continue;
    if (email.includes('@resource.calendar.google.com')) continue;
    if (!email) continue;
    if (!attendeesByEmail.has(email)) {
      const slackUser = resolveAttendee(email);
      attendeesByEmail.set(email, {
        email,
        calendarName: a.displayName || '',
        slackId: slackUser?.id || '',
        slackUsername: slackUser?.name || '',
        slackRealName: slackUser ? buildFullName(slackUser) : '',
        slackDisplayName: slackUser?.profile?.display_name || '',
        eventTitles: []
      });
    }
    attendeesByEmail.get(email).eventTitles.push(title);
  }
}

const attendees = [...attendeesByEmail.values()];
const sevenDaysAgo = new Date(Date.now() - 7 * 86400000).toISOString().slice(0, 10);

const queryParts = [];
for (const a of attendees) {
  if (a.slackId) {
    queryParts.push(`<@${a.slackId}>`);
    queryParts.push(`from:<@${a.slackId}>`);
  }
  if (a.slackRealName && a.slackRealName.includes(' ')) {
    queryParts.push(`"${a.slackRealName}"`);
  }
}

const slackQuery = queryParts.length > 0
  ? `(${[...new Set(queryParts)].join(' OR ')}) after:${sevenDaysAgo}`
  : '';

return [{
  json: {
    slackQuery,
    attendees,
    sevenDaysAgo,
    debug: {
      slackUserCount: slackUsers.length,
      attendeesResolved: attendees.filter(a => a.slackId).length,
      attendeesUnresolved: attendees.filter(a => !a.slackId).length
    }
  }
}];
